code.Python3:
import sys
def main():
    data=sys.stdin.read().strip().split()
    if not data:
        return
    it=iter(data)
    n=int(next(it))
    ans=-1
    for i in range(n):
        val=int(next(it))
        if ans==-1 and val==8:
            ans=i
    sys.stdout.write(str(ans))
if __name__=='__main__':
    main()

